parameters.jsCode:
const body = $input.first().json.body || $input.first().json;
const user_id = body.user_id || null;
const organization_id = body.organization_id || body.org_id || null;
const workspace_id = body.workspace_id || null;
const new_plan = body.new_plan || body.plan || null;
const old_plan = body.old_plan || 'starter';
const stripe_subscription_id = body.stripe_subscription_id || null;
if (!user_id) throw new Error('user_id is required');
if (!new_plan) throw new Error('new_plan is required');
const VALID_PLANS = ['starter', 'growth', 'pro', 'accelerator'];
if (!VALID_PLANS.includes(new_plan)) throw new Error(`Invalid plan: ${new_plan}`);
return [{ json: { user_id, organization_id, workspace_id, new_plan, old_plan, stripe_subscription_id, now: new Date().toISOString() } }];

